using namespace rvc;
using namespace rvc::test;

namespace {

void testLeftPriorityStrategy() {
    const LeftPriorityAvoidanceStrategy strategy;

    assert(strategy.decideOnFrontObstacle({false, false}) == AvoidanceAction::TurnLeft);
    assert(strategy.decideOnFrontObstacle({true, false}) == AvoidanceAction::TurnRight);
    assert(strategy.decideOnFrontObstacle({false, true}) == AvoidanceAction::TurnLeft);
    assert(strategy.decideOnFrontObstacle({true, true}) == AvoidanceAction::MoveBackward);

    assert(strategy.decideWhileBackward({true, true}, {false, true}) == AvoidanceAction::TurnLeft);
    assert(strategy.decideWhileBackward({true, true}, {true, false}) == AvoidanceAction::TurnRight);
    assert(strategy.decideWhileBackward({true, true}, {false, false}) == AvoidanceAction::TurnLeft);
    assert(strategy.decideWhileBackward({true, true}, {true, true}) ==
           AvoidanceAction::KeepBackward);
}

void testCleaningManagerPowerUpExtension() {
    FakeCleaningMotor cleaningMotor;
    FakeDustSensor dustSensor;
    FakeTimer powerTimer;
    CleaningManager manager{cleaningMotor, dustSensor, powerTimer};

    manager.start();
    assert(manager.currentState() == CleaningState::Normal);
    assert(cleaningMotor.lastState() == CleaningState::Normal);

    manager.onDustDetected(MovementState::Forward);
    assert(manager.currentState() == CleaningState::PowerUp);
    assert(cleaningMotor.lastState() == CleaningState::PowerUp);

    dustSensor.dustDetected = true;
    powerTimer.expire();
    manager.tick();
    assert(manager.currentState() == CleaningState::PowerUp);
    assert(powerTimer.startCount() == 2);

    dustSensor.dustDetected = false;
    powerTimer.expire();
    manager.tick();
    assert(manager.currentState() == CleaningState::Normal);
    assert(cleaningMotor.lastState() == CleaningState::Normal);
}

void testCleaningManagerDefersDustWhileAvoiding() {
    FakeCleaningMotor cleaningMotor;
    FakeDustSensor dustSensor;
    FakeTimer powerTimer;
    CleaningManager manager{cleaningMotor, dustSensor, powerTimer};

    manager.start();
    manager.onDustDetected(MovementState::Backward);
    assert(manager.currentState() == CleaningState::Normal);
    assert(manager.pendingPowerUp());

    manager.onMovementStateChanged(MovementState::Forward);
    assert(manager.currentState() == CleaningState::PowerUp);
    assert(!manager.pendingPowerUp());
}

void testMovementManagerTurnCompletion() {
    FakeMovementMotor motor;
    FakeTimer turnTimer;
    MovementManager manager{motor, turnTimer};

    manager.turnLeft();
    assert(manager.currentCommand() == MovementCommand::TurnLeft);
    assert(!manager.isTurnComplete());

    turnTimer.expire();
    assert(manager.isTurnComplete());
}

void testControllerStartStopInitializesAndShutsDownSensors() {
    FakeFrontObstacleSensor frontSensor;
    FakeSideObstacleSensor sideSensor;
    FakeDustSensor dustSensor;
    FakeMovementMotor movementMotor;
    FakeCleaningMotor cleaningMotor;
    FakeTimer turnTimer;
    FakeTimer powerTimer;
    MovementManager movement{movementMotor, turnTimer};
    CleaningManager cleaning{cleaningMotor, dustSensor, powerTimer};
    LeftPriorityAvoidanceStrategy strategy;
    RvcController controller{frontSensor, sideSensor, dustSensor, movement, cleaning, strategy};

    controller.startCleaning();
    assert(controller.movementState() == MovementState::Forward);
    assert(frontSensor.initialized);
    assert(sideSensor.initialized);
    assert(dustSensor.initialized);
    assert(cleaning.currentState() == CleaningState::Normal);
    assert(movement.currentCommand() == MovementCommand::Forward);

    controller.stopCleaning();
    assert(controller.movementState() == MovementState::Off);
    assert(!frontSensor.initialized);
    assert(!sideSensor.initialized);
    assert(!dustSensor.initialized);
    assert(cleaning.currentState() == CleaningState::Off);
    assert(movement.currentCommand() == MovementCommand::Stop);
}

void testFrontObstacleOnlyTurnsLeftThenForward() {
    FakeFrontObstacleSensor frontSensor;
    FakeSideObstacleSensor sideSensor;
    FakeDustSensor dustSensor;
    FakeMovementMotor movementMotor;
    FakeCleaningMotor cleaningMotor;
    FakeTimer turnTimer;
    FakeTimer powerTimer;
    MovementManager movement{movementMotor, turnTimer};
    CleaningManager cleaning{cleaningMotor, dustSensor, powerTimer};
    LeftPriorityAvoidanceStrategy strategy;
