    assert(controller.movementState() == MovementState::TurningLeft);
    assert(movement.currentCommand() == MovementCommand::TurnLeft);
    assert(cleaning.currentState() == CleaningState::Normal);

    turnTimer.expire();
    controller.tick();
    assert(controller.movementState() == MovementState::Forward);
    assert(movement.currentCommand() == MovementCommand::Forward);
}

