namespace rvc {

Direction DefaultAvoidStrategy::decideDirection(bool front, bool left, bool right) {
    const LeftPriorityAvoidanceStrategy strategy;
    const AvoidanceAction action = strategy.decideOnFrontObstacle(
        {.leftDetected = left, .rightDetected = right});
    if (front && action == AvoidanceAction::TurnRight) {
        return Direction::RIGHT;
    }
    if (front && action == AvoidanceAction::MoveBackward) {
        return Direction::BACKWARD;
    }
    if (front) {
        return Direction::LEFT;
    }
    return Direction::FORWARD;
}

bool DefaultAvoidStrategy::needsReverse(bool front, bool left, bool right) {
    return front && left && right;
}

RVCController::RVCController(IObstacleSensor& obstacleSensor,
                             IDustSensor& dustSensor,
                             IMotor& motor,
                             ICleaner& cleaner,
                             MovementManager& movementManager,
                             CleaningManager& cleaningManager,
                             ObstacleSensorSubject& obstacleSubject,
                             DustSensorSubject& dustSubject)
    : obstacleSensor_{obstacleSensor},
      dustSensor_{dustSensor},
      motor_{motor},
      cleaner_{cleaner},
      movementManager_{movementManager},
      cleaningManager_{cleaningManager},
