      cleaningMotorAdapter_{cleaner_},
      core_{frontAdapter_,
            sideAdapter_,
            dustSensor_,
            movementManager_,
            cleaningManager_,
            defaultStrategy_} {
    obstacleSubject_.attach(this);
    dustSubject_.attach(this);
}

